import { DarkTheme, DefaultTheme, ThemeProvider } from '@react-navigation/native';
import { Stack } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
import 'react-native-reanimated';

import { useColorScheme } from '@/hooks/use-color-scheme';

function RootLayoutNav() {
  const colorScheme = useColorScheme();
  const { isSignedIn, isLoading } = useAuth();

  if (isLoading) {
    return <LoadingSpinner />;
  }

  return (
    <ThemeProvider value={colorScheme === 'dark' ? DarkTheme : DefaultTheme}>
      <Stack>
        <Stack.Screen name="(tabs)" options={{ headerShown: false }} />
        <Stack.Screen name="modal" options={{ presentation: 'modal', title: 'Modal' }} />
      <Stack screenOptions={{ headerShown: false }}>
        {isSignedIn ? (
          <>
export const unstable_settings = {
  anchor: '(tabs)',
};

          </>
        ) : (
          <>
            <Stack.Screen
              name="login"
              component={LoginScreen}
              options={{ animationEnabled: false }}
            />
            <Stack.Screen
              name="register"
              component={RegisterScreen}
              options={{ animationEnabled: false }}
            />
          </>
        )}
      </Stack>
      <StatusBar style="auto" />
    </ThemeProvider>
  );
}

export default function RootLayout() {
  return (
    <AuthProvider>
      <UserProvider>
        <PostsProvider>
          <RootLayoutNav />
        </PostsProvider>
      </UserProvider>
    </AuthProvider>
  );
}

import { useEffect } from 'react';
import { DarkTheme, DefaultTheme, ThemeProvider } from '@react-navigation/native';
import { Stack } from 'expo-router';
import { StatusBar } from 'expo-status-bar';
import 'react-native-reanimated';

import { useColorScheme } from '@/hooks/use-color-scheme';
import { AuthProvider, useAuth } from '@/contexts/AuthContext';
import { UserProvider } from '@/contexts/UserContext';
import { PostsProvider } from '@/contexts/PostsContext';
import LoadingSpinner from '@/components/ui/LoadingSpinner';

function RootLayoutNav() {
  const colorScheme = useColorScheme();
  const { isSignedIn, isLoading } = useAuth();

  if (isLoading) {
    return <LoadingSpinner />;
  }

  return (
    <ThemeProvider value={colorScheme === 'dark' ? DarkTheme : DefaultTheme}>
      <Stack screenOptions={{ headerShown: false }}>
        {isSignedIn ? (
          <>
            <Stack.Screen name="(tabs)" options={{ animationEnabled: false }} />
            <Stack.Screen name="post/[id]" options={{ presentation: 'card' }} />
            <Stack.Screen name="modal" options={{ presentation: 'modal' }} />
          </>
        ) : (
          <>
            <Stack.Screen
              name="login"
              options={{ animationEnabled: false }}
            />
            <Stack.Screen
              name="register"
              options={{ animationEnabled: false }}
            />
          </>
        )}
      </Stack>
      <StatusBar style="auto" />
    </ThemeProvider>
  );
}

export default function RootLayout() {
  return (
    <AuthProvider>
      <UserProvider>
        <PostsProvider>
          <RootLayoutNav />
        </PostsProvider>
      </UserProvider>
    </AuthProvider>
  );
}

import React, { useEffect, useState } from 'react';
import {
  View,
  StyleSheet,
  ScrollView,
  KeyboardAvoidingView,
  Platform,
  Text,
  TouchableOpacity,
  SafeAreaView,
  TextInput,
  Alert,
} from 'react-native';
import { usePosts } from '@/contexts/PostsContext';
import { useRouter, useLocalSearchParams } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import CustomButton from '@/components/ui/CustomButton';
import ErrorMessage from '@/components/ui/ErrorMessage';
import SuccessMessage from '@/components/ui/SuccessMessage';
import LoadingSpinner from '@/components/ui/LoadingSpinner';
import Header from '@/components/ui/Header';
import PostCard from '@/components/ui/PostCard';
import { Post } from '@/types';
import { postService } from '@/services/posts.service';

const COLORS = {
  primary: '#2563EB',
  secondary: '#06B6D4',
  background: '#F8FAFC',
  white: '#FFFFFF',
  text: '#1F2937',
  textLight: '#6B7280',
  border: '#E5E7EB',
};

export default function PostDetailScreen() {
  const { id } = useLocalSearchParams();
  const router = useRouter();
  const { publishPost, updatePost, deletePost, isLoading } = usePosts();

  const [post, setPost] = useState<Post | null>(null);
  const [isLoadingPost, setIsLoadingPost] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [isEditing, setIsEditing] = useState(false);
  const [editedCaption, setEditedCaption] = useState('');
  const [editedHashtags, setEditedHashtags] = useState<string[]>([]);
  const [hashtagInput, setHashtagInput] = useState('');

  useEffect(() => {
    fetchPost();
  }, [id]);

  const fetchPost = async () => {
    try {
      setIsLoadingPost(true);
      setError(null);

      if (typeof id === 'string') {
        const fetchedPost = await postService.getPost(id);
        setPost(fetchedPost);
        setEditedCaption(fetchedPost.caption);
        setEditedHashtags(fetchedPost.hashtags);
      }
    } catch (err: any) {
      setError(err?.response?.data?.message || 'Error al cargar la publicación');
    } finally {
      setIsLoadingPost(false);
    }
  };

  const handleSave = async () => {
    if (!post) return;

    try {
      setError(null);
      await updatePost(post.id, {
        caption: editedCaption,
        hashtags: editedHashtags,
      });
      setSuccess('Publicación actualizada');
      setIsEditing(false);
      setTimeout(() => {
        setSuccess(null);
        fetchPost();
      }, 1500);
    } catch (err: any) {
      setError(err?.response?.data?.message || 'Error al actualizar');
    }
  };

  const handlePublish = async () => {
    if (!post) return;

    Alert.alert(
      'Publicar',
      '¿Deseas publicar esta publicación en Instagram?',
      [
        { text: 'Cancelar', style: 'cancel' },
        {
          text: 'Publicar',
          onPress: async () => {
            try {
              setError(null);
              await publishPost(post.id, 'instagram');
              setSuccess('¡Publicación publicada exitosamente!');
              setTimeout(() => {
                setSuccess(null);
                fetchPost();
              }, 1500);
            } catch (err: any) {
              setError(err?.response?.data?.message || 'Error al publicar');
            }
          },
        },
      ]
    );
  };

  const handleDelete = () => {
    Alert.alert(
      'Eliminar Publicación',
      '¿Estás seguro de que deseas eliminar esta publicación?',
      [
        { text: 'Cancelar', style: 'cancel' },
        {
          text: 'Eliminar',
          onPress: async () => {
            try {
              await deletePost(post!.id);
              setSuccess('Publicación eliminada');
              setTimeout(() => router.back(), 1000);
            } catch (err: any) {
              setError(err?.response?.data?.message || 'Error al eliminar');
            }
          },
          style: 'destructive',
        },
      ]
    );
  };

  const addHashtag = () => {
    if (hashtagInput.trim()) {
      const newHashtag = hashtagInput.trim().replace('#', '');
      if (!editedHashtags.includes(newHashtag)) {
        setEditedHashtags([...editedHashtags, newHashtag]);
      }
      setHashtagInput('');
    }
  };

  const removeHashtag = (index: number) => {
    setEditedHashtags(editedHashtags.filter((_, i) => i !== index));
  };

  if (isLoadingPost) {
    return <LoadingSpinner />;
  }

  if (!post) {
    return (
      <SafeAreaView style={styles.container}>
        <Header title="Publicación" />
        <View style={styles.errorContainer}>
          <Text style={styles.errorText}>No se pudo cargar la publicación</Text>
          <CustomButton title="Volver" onPress={() => router.back()} />
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <Header title="Detalles de Publicación" />

      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.content}>
        <ScrollView
          contentContainerStyle={styles.scrollContent}
          showsVerticalScrollIndicator={false}>
          {error && (
            <ErrorMessage 
              message={error} 
              onClose={() => setError(null)}
              containerStyle={styles.messageContainer}
            />
          )}
          {success && (
            <SuccessMessage 
              message={success}
              containerStyle={styles.messageContainer}
            />
          )}

          {isEditing ? (
            <>
              <Text style={styles.label}>Contenido</Text>
              <TextInput
                style={styles.textInput}
                placeholder="Contenido"
                value={editedCaption}
                onChangeText={setEditedCaption}
                multiline
                numberOfLines={5}
                textAlignVertical="top"
              />

              <Text style={styles.label}>Hashtags</Text>
              <View style={styles.hashtagInputContainer}>
                <TextInput
                  style={styles.hashtagInput}
                  placeholder="Agregar hashtag"
                  value={hashtagInput}
                  onChangeText={setHashtagInput}
                  onSubmitEditing={addHashtag}
                />
                <TouchableOpacity
                  onPress={addHashtag}
                  style={styles.addButton}>
                  <Ionicons name="add" size={20} color={COLORS.white} />
                </TouchableOpacity>
              </View>

              {editedHashtags.length > 0 && (
                <View style={styles.hashtagsList}>
                  {editedHashtags.map((tag, index) => (
                    <View key={index} style={styles.hashtagBadge}>
                      <Text style={styles.hashtagText}>#{tag}</Text>
                      <TouchableOpacity onPress={() => removeHashtag(index)}>
                        <Ionicons name="close" size={14} color={COLORS.white} />
                      </TouchableOpacity>
                    </View>
                  ))}
                </View>
              )}

              <View style={styles.buttonContainer}>
                <CustomButton
                  title="Cancelar"
                  onPress={() => {
                    setIsEditing(false);
                    setEditedCaption(post.caption);
                    setEditedHashtags(post.hashtags);
                  }}
                  variant="secondary"
                  style={{ flex: 1, marginRight: 8 }}
                />
                <CustomButton
                  title="Guardar"
                  onPress={handleSave}
                  loading={isLoading}
                  style={{ flex: 1 }}
                />
              </View>
            </>
          ) : (
            <>
              <PostCard post={post} />

              <View style={styles.infoSection}>
                <Text style={styles.sectionTitle}>Información</Text>

                <View style={styles.infoItem}>
                  <Text style={styles.infoLabel}>Estado</Text>
                  <Text style={styles.infoValue}>{post.status}</Text>
                </View>

                <View style={styles.infoItem}>
                  <Text style={styles.infoLabel}>Creado</Text>
                  <Text style={styles.infoValue}>
                    {new Date(post.createdAt).toLocaleDateString('es-ES')}
                  </Text>
                </View>
              </View>

              <View style={styles.actionButtons}>
                {post.status === 'draft' && (
                  <CustomButton
                    title="Publicar en Instagram"
                    onPress={handlePublish}
                    loading={isLoading}
                    style={{ marginBottom: 8 }}
                  />
                )}

                <CustomButton
                  title="Editar"
                  onPress={() => setIsEditing(true)}
                  variant="secondary"
                  style={{ marginBottom: 8 }}
                />

                <CustomButton
                  title="Eliminar"
                  onPress={handleDelete}
                  variant="danger"
                />
              </View>
            </>
          )}
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
