import React, { createContext, useContext, useEffect, useState } from 'react';
import { User, AuthResponse } from '@/types';
import { authService } from '@/services/auth.service';
import { LoginRequest, RegisterRequest } from '@/types';

interface AuthContextType {
  user: User | null;
  isLoading: boolean;
  isSignedIn: boolean;
  login: (credentials: LoginRequest) => Promise<void>;
  register: (data: RegisterRequest) => Promise<void>;
  logout: () => Promise<void>;
  restoreToken: () => Promise<void>;
  error: string | null;
  setError: (error: string | null) => void;
}

const AuthContext = createContext<AuthContextType>({
  user: null,
  isLoading: true,
  isSignedIn: false,
  login: async () => {},
  register: async () => {},
  logout: async () => {},
  restoreToken: async () => {},
  error: null,
  setError: () => {},
});

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Restore token on app launch
  useEffect(() => {
    restoreToken();
  }, []);

  const restoreToken = async () => {
    try {
      setIsLoading(true);
      setError(null);

      const token = await authService.getStoredToken();
      if (token) {
        const storedUser = await authService.getStoredUser();
        if (storedUser) {
          setUser(storedUser);
        }
      }
    } catch (err) {
      setError('Error restoring token');
      console.error('Error restoring token:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const login = async (credentials: LoginRequest) => {
    try {
      setIsLoading(true);
      setError(null);

      const response = await authService.login(credentials);
      setUser(response.user);
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error during login';
      setError(errorMessage);
      throw err;
    } finally {
      setIsLoading(false);
    }
  };

  const register = async (data: RegisterRequest) => {
    try {
      setIsLoading(true);
      setError(null);

      const response = await authService.register(data);
      setUser(response.user);
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error during registration';
      setError(errorMessage);
      throw err;
    } finally {
      setIsLoading(false);
    }
  };

  const logout = async () => {
    try {
      setIsLoading(true);
      setError(null);

      await authService.logout();
      setUser(null);
    } catch (err) {
      setError('Error during logout');
      console.error('Error during logout:', err);
    } finally {
      setIsLoading(false);
    }
  };

  const value = {
    user,
    isLoading,
    isSignedIn: !!user,
    login,
    register,
    logout,
    restoreToken,
    error,
    setError,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useCallback } from 'react';
import { Post, CreatePostRequest, UpdatePostRequest } from '@/types';
import { postService } from '@/services/posts.service';

interface PostsContextType {
  posts: Post[];
  isLoading: boolean;
  error: string | null;
  fetchPosts: () => Promise<void>;
  createPost: (data: CreatePostRequest) => Promise<Post>;
  updatePost: (postId: string, data: UpdatePostRequest) => Promise<void>;
  deletePost: (postId: string) => Promise<void>;
  publishPost: (postId: string, platform: string) => Promise<void>;
  setError: (error: string | null) => void;
}

const PostsContext = createContext<PostsContextType>({
  posts: [],
  isLoading: false,
  error: null,
  fetchPosts: async () => {},
  createPost: async () => ({} as Post),
  updatePost: async () => {},
  deletePost: async () => {},
  publishPost: async () => {},
  setError: () => {},
});

export const PostsProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [posts, setPosts] = useState<Post[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const fetchPosts = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);

      const fetchedPosts = await postService.getPosts();
      setPosts(fetchedPosts);
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error fetching posts';
      setError(errorMessage);
      console.error('Error fetching posts:', err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const createPost = useCallback(async (data: CreatePostRequest) => {
    try {
      setIsLoading(true);
      setError(null);

      const newPost = await postService.createPost(data);
      setPosts((prev) => [newPost, ...prev]);

      return newPost;
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error creating post';
      setError(errorMessage);
      console.error('Error creating post:', err);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const updatePost = useCallback(async (postId: string, data: UpdatePostRequest) => {
    try {
      setIsLoading(true);
      setError(null);

      const updatedPost = await postService.updatePost(postId, data);
      setPosts((prev) => prev.map((post) => (post.id === postId ? updatedPost : post)));
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error updating post';
      setError(errorMessage);
      console.error('Error updating post:', err);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const deletePost = useCallback(async (postId: string) => {
    try {
      setIsLoading(true);
      setError(null);

      await postService.deletePost(postId);
      setPosts((prev) => prev.filter((post) => post.id !== postId));
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error deleting post';
      setError(errorMessage);
      console.error('Error deleting post:', err);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const publishPost = useCallback(async (postId: string, platform: string) => {
    try {
      setIsLoading(true);
      setError(null);

      await postService.publishPost(postId, platform);

      // Update post status in local state
      setPosts((prev) =>
        prev.map((post) =>
          post.id === postId ? { ...post, status: 'published' as const } : post
        )
      );
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error publishing post';
      setError(errorMessage);
      console.error('Error publishing post:', err);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const value = {
    posts,
    isLoading,
    error,
    fetchPosts,
    createPost,
    updatePost,
    deletePost,
    publishPost,
    setError,
  };

  return <PostsContext.Provider value={value}>{children}</PostsContext.Provider>;
};

export const usePosts = () => {
  const context = useContext(PostsContext);
  if (!context) {
    throw new Error('usePosts must be used within a PostsProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useCallback, useEffect } from 'react';
import { User } from '@/types';
import { userService } from '@/services/user.service';
import { useAuth } from './AuthContext';

interface UserContextType {
  userProfile: User | null;
  isLoading: boolean;
  error: string | null;
  fetchUserProfile: (userId: string) => Promise<void>;
  updateUserProfile: (userId: string, data: Partial<User>) => Promise<void>;
  setError: (error: string | null) => void;
}

const UserContext = createContext<UserContextType>({
  userProfile: null,
  isLoading: false,
  error: null,
  fetchUserProfile: async () => {},
  updateUserProfile: async () => {},
  setError: () => {},
});

export const UserProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [userProfile, setUserProfile] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const { user } = useAuth();

  // Auto-fetch user profile when auth user changes
  useEffect(() => {
    if (user?.id) {
      fetchUserProfile(user.id);
    }
  }, [user?.id]);

  const fetchUserProfile = useCallback(async (userId: string) => {
    try {
      setIsLoading(true);
      setError(null);

      const profile = await userService.getUser(userId);
      setUserProfile(profile);
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error fetching user profile';
      setError(errorMessage);
      console.error('Error fetching user profile:', err);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const updateUserProfile = useCallback(async (userId: string, data: Partial<User>) => {
    try {
      setIsLoading(true);
      setError(null);

      const updatedProfile = await userService.updateUser(userId, data);
      setUserProfile(updatedProfile);
    } catch (err: any) {
      const errorMessage = err?.response?.data?.message || 'Error updating user profile';
      setError(errorMessage);
      console.error('Error updating user profile:', err);
      throw err;
    } finally {
      setIsLoading(false);
    }
  }, []);

  const value = {
    userProfile,
    isLoading,
    error,
    fetchUserProfile,
    updateUserProfile,
    setError,
  };

  return <UserContext.Provider value={value}>{children}</UserContext.Provider>;
};

export const useUser = () => {
  const context = useContext(UserContext);
  if (!context) {
    throw new Error('useUser must be used within a UserProvider');
  }
  return context;
};

import React, { useState } from 'react';
import {
  View,
  StyleSheet,
  ScrollView,
  KeyboardAvoidingView,
  Platform,
  Text,
  SafeAreaView,
  TouchableOpacity,
  TextInput,
} from 'react-native';
import { usePosts } from '@/contexts/PostsContext';
import { useRouter } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import CustomButton from '@/components/ui/CustomButton';
import CustomInput from '@/components/ui/CustomInput';
import ErrorMessage from '@/components/ui/ErrorMessage';
import SuccessMessage from '@/components/ui/SuccessMessage';
import LoadingSpinner from '@/components/ui/LoadingSpinner';
import { geminiService } from '@/services/gemini.service';
import { validatePrompt } from '@/utils/validation';

const COLORS = {
  primary: '#2563EB',
  secondary: '#06B6D4',
  background: '#F8FAFC',
  white: '#FFFFFF',
  text: '#1F2937',
  textLight: '#6B7280',
  border: '#E5E7EB',
};

export default function CreatePostScreen() {
  const { createPost, isLoading: isCreatingPost } = usePosts();
  const router = useRouter();

  const [step, setStep] = useState<'prompt' | 'content'>('prompt');
  const [prompt, setPrompt] = useState('');
  const [caption, setCaption] = useState('');
  const [hashtags, setHashtags] = useState<string[]>([]);
  const [hashtagInput, setHashtagInput] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [isGenerating, setIsGenerating] = useState(false);

  const handleGenerateContent = async () => {
    if (!validatePrompt(prompt)) {
      setError('El prompt debe tener al menos 10 caracteres');
      return;
    }

    try {
      setIsGenerating(true);
      setError(null);

      const result = await geminiService.generateContent(prompt);
      setCaption(result.caption);
      setHashtags(result.hashtags);
      setStep('content');
    } catch (err: any) {
      setError(
        err?.response?.data?.message ||
        'Error al generar contenido. Intenta de nuevo.'
      );
    } finally {
      setIsGenerating(false);
    }
  };

  const addHashtag = () => {
    if (hashtagInput.trim()) {
      const newHashtag = hashtagInput.trim().replace('#', '');
      if (!hashtags.includes(newHashtag)) {
        setHashtags([...hashtags, newHashtag]);
      }
      setHashtagInput('');
    }
  };

  const removeHashtag = (index: number) => {
    setHashtags(hashtags.filter((_, i) => i !== index));
  };

  const handleCreatePost = async () => {
    if (!caption.trim()) {
      setError('El contenido no puede estar vacío');
      return;
    }

    try {
      setError(null);
      await createPost({
        caption,
        hashtags,
        title: prompt.substring(0, 50),
      });

      setSuccess('Publicación creada exitosamente');
      setTimeout(() => {
        router.push('/(tabs)/posts');
      }, 1500);
    } catch (err: any) {
      setError(
        err?.response?.data?.message ||
        'Error al crear la publicación'
      );
    }
  };

  if (step === 'prompt') {
    return (
      <KeyboardAvoidingView
        behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
        style={styles.container}>
        <SafeAreaView style={styles.safeArea}>
          <ScrollView
            contentContainerStyle={styles.scrollContent}
            showsVerticalScrollIndicator={false}>
            {/* Header */}
            <View style={styles.header}>
              <TouchableOpacity
                onPress={() => router.back()}
                style={styles.backButton}>
                <Ionicons name="chevron-back" size={24} color={COLORS.primary} />
              </TouchableOpacity>
              <Text style={styles.title}>Generar Contenido</Text>
              <View style={{ width: 24 }} />
            </View>

            {/* Info */}
            <View style={styles.infoCard}>
              <Ionicons name="lightbulb" size={24} color={COLORS.secondary} />
              <Text style={styles.infoText}>
                Describe qué deseas promocionar y nuestra IA generará contenido
              </Text>
            </View>

            {error && (
              <ErrorMessage 
                message={error} 
                onClose={() => setError(null)}
              />
            )}

            {/* Prompt Input */}
            <Text style={styles.label}>¿Qué deseas promocionar?</Text>
            <TextInput
              style={styles.promptInput}
              placeholder="Ej: Hamburguesa gourmet con queso artesanal"
              placeholderTextColor={COLORS.textLight}
              value={prompt}
              onChangeText={(text) => {
                setPrompt(text);
                if (error) setError(null);
              }}
              multiline
              numberOfLines={4}
              textAlignVertical="top"
            />

            <Text style={styles.helperText}>
              Cuántos más detalles proporciones, mejor será el contenido
            </Text>

            {/* Examples */}
            <View style={styles.examplesContainer}>
              <Text style={styles.examplesTitle}>Ejemplos:</Text>
              {[
                'Promocionar un descuento especial de verano',
                'Lanzar un nuevo producto de belleza',
                'Aumentar asistencia al restaurante en fin de semana',
              ].map((example, index) => (
                <TouchableOpacity
                  key={index}
                  style={styles.exampleItem}
                  onPress={() => setPrompt(example)}>
                  <Text style={styles.exampleText}>{example}</Text>
                </TouchableOpacity>
              ))}
            </View>
          </ScrollView>

          {/* Generate Button */}
          <View style={styles.footer}>
            <CustomButton
              title={isGenerating ? 'Generando...' : 'Generar Contenido'}
              onPress={handleGenerateContent}
              loading={isGenerating}
              disabled={isGenerating || !prompt.trim()}
            />
          </View>
        </SafeAreaView>
      </KeyboardAvoidingView>
    );
  }

  // Content editing step
  return (
    <KeyboardAvoidingView
      behavior={Platform.OS === 'ios' ? 'padding' : 'height'}
      style={styles.container}>
      <SafeAreaView style={styles.safeArea}>
        <ScrollView
          contentContainerStyle={styles.scrollContent}
          showsVerticalScrollIndicator={false}>
          {/* Header */}
          <View style={styles.header}>
            <TouchableOpacity
              onPress={() => setStep('prompt')}
              style={styles.backButton}>
              <Ionicons name="chevron-back" size={24} color={COLORS.primary} />
            </TouchableOpacity>
            <Text style={styles.title}>Editar Contenido</Text>
            <View style={{ width: 24 }} />
          </View>

          {error && (
            <ErrorMessage 
              message={error} 
              onClose={() => setError(null)}
            />
          )}

          {success && (
            <SuccessMessage message={success} />
          )}

          {/* Caption */}
          <Text style={styles.label}>Contenido</Text>
          <TextInput
            style={styles.captionInput}
            placeholder="Edita el contenido generado"
            placeholderTextColor={COLORS.textLight}
            value={caption}
            onChangeText={(text) => {
              setCaption(text);
              if (error) setError(null);
            }}
            multiline
            numberOfLines={6}
            textAlignVertical="top"
          />

          {/* Hashtags */}
          <Text style={styles.label}>Hashtags</Text>
          <View style={styles.hashtagInput}>
            <TextInput
              style={styles.hashtagInputField}
              placeholder="Agregar hashtag"
              placeholderTextColor={COLORS.textLight}
              value={hashtagInput}
              onChangeText={setHashtagInput}
              onSubmitEditing={addHashtag}
            />
            <TouchableOpacity
              onPress={addHashtag}
              style={styles.addHashtagButton}>
              <Ionicons name="add" size={20} color={COLORS.white} />
            </TouchableOpacity>
          </View>

          {/* Hashtags List */}
          {hashtags.length > 0 && (
            <View style={styles.hashtagsList}>
              {hashtags.map((tag, index) => (
                <View key={index} style={styles.hashtagBadge}>
                  <Text style={styles.hashtagBadgeText}>#{tag}</Text>
                  <TouchableOpacity
                    onPress={() => removeHashtag(index)}
                    hitSlop={{ top: 6, bottom: 6, left: 6, right: 6 }}>
                    <Ionicons name="close" size={14} color={COLORS.white} />
                  </TouchableOpacity>
                </View>
              ))}
            </View>
          )}
        </ScrollView>

        {/* Buttons */}
        <View style={styles.footer}>
          <CustomButton
            title="Volver"
            onPress={() => setStep('prompt')}
            variant="secondary"
            style={{ flex: 1, marginRight: 8 }}
          />
          <CustomButton
            title="Crear Publicación"
            onPress={handleCreatePost}
            loading={isCreatingPost}
            disabled={isCreatingPost}
            style={{ flex: 1 }}
          />
        </View>
      </SafeAreaView>
    </KeyboardAvoidingView>
  );
}

