import React, { useEffect } from 'react';
import {
  View,
  StyleSheet,
  SafeAreaView,
  ScrollView,
  Text,
  RefreshControl,
} from 'react-native';
import { usePosts } from '@/contexts/PostsContext';
import { Ionicons } from '@expo/vector-icons';
import LoadingSpinner from '@/components/ui/LoadingSpinner';
import Header from '@/components/ui/Header';

const COLORS = {
  primary: '#2563EB',
  secondary: '#06B6D4',
  success: '#10B981',
  warning: '#F59E0B',
  background: '#F8FAFC',
  white: '#FFFFFF',
  text: '#1F2937',
  textLight: '#6B7280',
  border: '#E5E7EB',
};

interface TimelineEvent {
  id: string;
  type: 'created' | 'published' | 'scheduled' | 'edited';
  title: string;
  description: string;
  date: Date;
  icon: string;
  color: string;
}

export default function HistoryScreen() {
  const { posts, isLoading, fetchPosts } = usePosts();
  const [refreshing, setRefreshing] = React.useState(false);
  const [events, setEvents] = React.useState<TimelineEvent[]>([]);

  useEffect(() => {
    fetchPosts();
  }, []);

  useEffect(() => {
    // Build timeline events from posts
    const timelineEvents: TimelineEvent[] = [];

    posts.forEach((post) => {
      // Created event
      timelineEvents.push({
        id: `${post.id}-created`,
        type: 'created',
        title: 'Publicación Creada',
        description:
          post.caption.substring(0, 50) + (post.caption.length > 50 ? '...' : ''),
        date: new Date(post.createdAt),
        icon: 'create',
        color: COLORS.primary,
      });

      // Published event
      if (post.status === 'published' && post.publishedAt) {
        timelineEvents.push({
          id: `${post.id}-published`,
          type: 'published',
          title: 'Publicación Publicada',
          description: 'Publicado en Instagram',
          date: new Date(post.publishedAt),
          icon: 'share-social',
          color: COLORS.success,
        });
      }
    });

    // Sort by date descending
    timelineEvents.sort((a, b) => b.date.getTime() - a.date.getTime());
    setEvents(timelineEvents);
  }, [posts]);

  const onRefresh = async () => {
    setRefreshing(true);
    await fetchPosts();
    setRefreshing(false);
  };

  if (isLoading && posts.length === 0) {
    return <LoadingSpinner />;
  }

  // Group events by date
  const groupedEvents = events.reduce(
    (acc, event) => {
      const dateKey = event.date.toLocaleDateString('es-ES', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
      });

      if (!acc[dateKey]) {
        acc[dateKey] = [];
      }
      acc[dateKey].push(event);
      return acc;
    },
    {} as Record<string, TimelineEvent[]>
  );

  return (
    <SafeAreaView style={styles.container}>
      <Header
        title="Historial"
        showBackButton={false}
      />

      <ScrollView
        contentContainerStyle={styles.scrollContent}
        refreshControl={
          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} />
        }
        showsVerticalScrollIndicator={false}>
        {/* Activity Summary */}
        <View style={styles.summaryContainer}>
          <View style={styles.summaryCard}>
            <Text style={styles.summaryNumber}>{posts.length}</Text>
            <Text style={styles.summaryLabel}>Publicaciones</Text>
          </View>
          <View style={styles.summaryCard}>
            <Text style={styles.summaryNumber}>
              {posts.filter((p) => p.status === 'published').length}
            </Text>
            <Text style={styles.summaryLabel}>Publicadas</Text>
          </View>
          <View style={styles.summaryCard}>
            <Text style={styles.summaryNumber}>
              {new Date().toLocaleDateString('es-ES', { day: '2-digit' })}
            </Text>
            <Text style={styles.summaryLabel}>Hoy</Text>
          </View>
        </View>

        {/* Timeline */}
        {events.length > 0 ? (
          Object.entries(groupedEvents).map(([dateKey, dayEvents]) => (
            <View key={dateKey} style={styles.daySection}>
              <Text style={styles.dayHeader}>{dateKey}</Text>

              {dayEvents.map((event, index) => (
                <View key={event.id} style={styles.timelineItem}>
                  {/* Timeline dot and line */}
                  <View style={styles.timelineIndicator}>
                    <View
                      style={[
                        styles.timelineDot,
                        { backgroundColor: event.color },
                      ]}>
                      <Ionicons name={event.icon as any} size={16} color="white" />
                    </View>
                    {index !== dayEvents.length - 1 && (
                      <View style={styles.timelineLine} />
                    )}
                  </View>

                  {/* Event content */}
                  <View style={styles.eventContent}>
                    <View style={styles.eventHeader}>
                      <Text style={styles.eventTitle}>{event.title}</Text>
                      <Text style={styles.eventTime}>
                        {event.date.toLocaleTimeString('es-ES', {
                          hour: '2-digit',
                          minute: '2-digit',
                        })}
                      </Text>
                    </View>
                    <Text style={styles.eventDescription} numberOfLines={1}>
                      {event.description}
                    </Text>
                  </View>
                </View>
              ))}
            </View>
          ))
        ) : (
          <View style={styles.emptyState}>
            <Ionicons name="time-outline" size={64} color={COLORS.textLight} />
            <Text style={styles.emptyStateTitle}>Sin actividad</Text>
            <Text style={styles.emptyStateDesc}>
              Tu historial de actividad aparecerá aquí
            </Text>
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

