  emptyStateButtonText: {
    color: COLORS.white,
    fontWeight: '600',
  },
});

import React, { useState } from 'react';
import {
  View,
  StyleSheet,
  SafeAreaView,
  ScrollView,
  Text,
  TouchableOpacity,
  TextInput,
  Alert,
} from 'react-native';
import { useAuth } from '@/contexts/AuthContext';
import { useUser } from '@/contexts/UserContext';
import { useRouter } from 'expo-router';
import { Ionicons } from '@expo/vector-icons';
import CustomButton from '@/components/ui/CustomButton';
import ErrorMessage from '@/components/ui/ErrorMessage';
import SuccessMessage from '@/components/ui/SuccessMessage';
import Header from '@/components/ui/Header';
import LoadingSpinner from '@/components/ui/LoadingSpinner';

const COLORS = {
  primary: '#2563EB',
  secondary: '#06B6D4',
  background: '#F8FAFC',
  white: '#FFFFFF',
  text: '#1F2937',
  textLight: '#6B7280',
  border: '#E5E7EB',
};

export default function ProfileScreen() {
  const { user: authUser, logout } = useAuth();
  const { userProfile, isLoading, updateUserProfile, error, setError } = useUser();
  const router = useRouter();

  const [isEditing, setIsEditing] = useState(false);
  const [editedName, setEditedName] = useState(userProfile?.name || '');
  const [editError, setEditError] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const handleSaveProfile = async () => {
    if (!editedName.trim()) {
      setEditError('El nombre no puede estar vacío');
      return;
    }

    try {
      setEditError(null);
      if (userProfile) {
        await updateUserProfile(userProfile.id, { name: editedName });
        setSuccessMessage('Perfil actualizado exitosamente');
        setIsEditing(false);
        setTimeout(() => setSuccessMessage(null), 3000);
      }
    } catch (err: any) {
      setEditError(err?.response?.data?.message || 'Error al actualizar el perfil');
    }
  };

  const handleLogout = () => {
    Alert.alert(
      'Cerrar Sesión',
      '¿Estás seguro de que deseas cerrar sesión?',
      [
        { text: 'Cancelar', onPress: () => {}, style: 'cancel' },
        {
          text: 'Cerrar Sesión',
          onPress: async () => {
            await logout();
            router.replace('/login');
          },
          style: 'destructive',
        },
      ]
    );
  };

  if (isLoading) {
    return <LoadingSpinner />;
  }

  return (
    <SafeAreaView style={styles.container}>
      <Header
        title="Mi Perfil"
        showBackButton={false}
      />

      <ScrollView contentContainerStyle={styles.scrollContent} showsVerticalScrollIndicator={false}>
        {/* User Header */}
        <View style={styles.userHeader}>
          <View style={styles.avatarContainer}>
            <Ionicons name="person-circle" size={80} color={COLORS.primary} />
          </View>
          <Text style={styles.userName}>{userProfile?.name}</Text>
          <Text style={styles.userEmail}>{userProfile?.email}</Text>
          {userProfile?.plan && (
            <View style={styles.planBadge}>
              <Text style={styles.planText}>{userProfile.plan}</Text>
            </View>
          )}
        </View>

        {/* Error Message */}
        {error && (
          <ErrorMessage 
            message={error} 
            onClose={() => setError(null)}
            containerStyle={styles.messageContainer}
          />
        )}
        {editError && (
          <ErrorMessage 
            message={editError} 
            onClose={() => setEditError(null)}
            containerStyle={styles.messageContainer}
          />
        )}
        {successMessage && (
          <SuccessMessage 
            message={successMessage}
            containerStyle={styles.messageContainer}
          />
        )}

        {/* Edit Mode */}
        {isEditing ? (
          <View style={styles.editSection}>
            <Text style={styles.sectionTitle}>Editar Información</Text>

            <View style={styles.formGroup}>
              <Text style={styles.label}>Nombre</Text>
              <TextInput
                style={styles.input}
                placeholder="Tu nombre"
                value={editedName}
                onChangeText={setEditedName}
              />
            </View>

            <View style={styles.editButtons}>
              <CustomButton
                title="Cancelar"
                onPress={() => {
                  setIsEditing(false);
                  setEditedName(userProfile?.name || '');
                }}
                variant="secondary"
                style={{ flex: 1, marginRight: 8 }}
              />
              <CustomButton
                title="Guardar"
                onPress={handleSaveProfile}
                loading={isLoading}
                style={{ flex: 1 }}
              />
            </View>
          </View>
        ) : (
          <>
            {/* Profile Info */}
            <View style={styles.infoSection}>
              <Text style={styles.sectionTitle}>Información</Text>

