// Auth Types
export interface LoginRequest {
  email: string;
  password: string;
}

export interface RegisterRequest {
  email: string;
  password: string;
  name: string;
}

export interface AuthResponse {
  access_token: string;
  user: User;
}

// User Types
export interface User {
  id: string;
  email: string;
  name: string;
  profileImage?: string;
  plan?: string;
  createdAt: string;
  updatedAt: string;
}

// Post Types
export interface Post {
  id: string;
  userId: string;
  title?: string;
  caption: string;
  hashtags: string[];
  image?: string;
  status: 'draft' | 'published' | 'scheduled';
  publishedAt?: string;
  createdAt: string;
  updatedAt: string;
}

export interface CreatePostRequest {
  caption: string;
  hashtags: string[];
  image?: string;
  title?: string;
}

export interface UpdatePostRequest {
  caption?: string;
  hashtags?: string[];
  image?: string;
  title?: string;
  status?: 'draft' | 'published' | 'scheduled';
}

// Gemini Types
export interface GeminiRequest {
  prompt: string;
}

export interface GeminiResponse {
  caption: string;
  hashtags: string[];
}

// Social Types
export interface SocialAccount {
  id: string;
  userId: string;
  platform: 'instagram' | 'facebook' | 'twitter';
  accountId: string;
  accountName: string;
  isConnected: boolean;
  connectedAt?: string;
}

export interface PublishRequest {
  platform: 'instagram' | 'facebook' | 'twitter';
  postId: string;
}

export interface PublishResponse {
  success: boolean;
  message: string;
  publishedAt: string;
}

// API Error Types
export interface ApiError {
  message: string;
  statusCode: number;
  error?: string;
}

export const validateEmail = (email: string): boolean => {
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
};

export const validatePassword = (password: string): { isValid: boolean; error?: string } => {
  if (password.length < 6) {
    return { isValid: false, error: 'La contraseña debe tener al menos 6 caracteres' };
  }
  if (!/[A-Z]/.test(password)) {
    return { isValid: false, error: 'La contraseña debe contener al menos una mayúscula' };
  }
  if (!/[0-9]/.test(password)) {
    return { isValid: false, error: 'La contraseña debe contener al menos un número' };
  }
  return { isValid: true };
};

export const validateName = (name: string): boolean => {
  return name.trim().length >= 2;
};

export const validatePrompt = (prompt: string): boolean => {
  return prompt.trim().length >= 10;
};

export const validateCaption = (caption: string): boolean => {
  return caption.trim().length > 0;
};

export const getErrorMessage = (error: any): string => {
  if (error?.response?.data?.message) {
    return error.response.data.message;
  }
  if (error?.message) {
    return error.message;
  }
  return 'Algo salió mal. Por favor, intenta de nuevo.';
};
